# scripts/notify-slack-release.py
import os
import re
import sys
import requests

SLACK_WEBHOOK = os.environ["SLACK_RELEASE_WEBHOOK"]
CHANGELOG_FILE = sys.argv[1] if len(sys.argv) > 1 else "CHANGELOG.md"
VERSION = sys.argv[2] if len(sys.argv) > 2 else "unreleased"

def extract_section(changelog: str, version: str, section: str) -> list[str]:
    """Extract entries from a named section in the given version block."""
    in_version = False
    in_section = False
    entries = []
    for line in changelog.split("\n"):
        if line.startswith(f"## [{version}]"):
            in_version = True
        elif in_version and line.startswith("## ["):
            break  # next version block
        if in_version and line.startswith(f"### {section}"):
            in_section = True
        elif in_version and line.startswith("### ") and in_section:
            in_section = False
        if in_section and line.startswith("- "):
            entries.append(line[2:])
    return entries

with open(CHANGELOG_FILE) as f:
    changelog = f.read()

prompt_changes = extract_section(changelog, VERSION, "Prompt Changes")
model_upgrades = extract_section(changelog, VERSION, "Model Upgrades")
features = extract_section(changelog, VERSION, "Features")

blocks = [
    {"type": "header", "text": {"type": "plain_text", "text": f"🚀 Release {VERSION}"}},
]
if prompt_changes:
    items = "\n".join(f"• {e}" for e in prompt_changes[:5])
    blocks.append({
        "type": "section",
        "text": {"type": "mrkdwn", "text": f"*⚡ Prompt Changes*\n{items}"}
    })
if model_upgrades:
    items = "\n".join(f"• {e}" for e in model_upgrades[:3])
    blocks.append({
        "type": "section",
        "text": {"type": "mrkdwn", "text": f"*🤖 Model Upgrades*\n{items}"}
    })

requests.post(SLACK_WEBHOOK, json={"blocks": blocks})
print(f"Notified Slack for release {VERSION}")
